mapper.select:
/* 1. ID: selectAdmList 2. 업무명: 관리자의 리스트 3. 업무설명: */ SELECT * FROM ( SELECT doc_seq, doc_title, cre_dtm, doc_stat, ans_dtm from CRBN_QNA WHERE party_cd = #{partyCd}
and doc_title like CONCAT('%',#{searchValue},'%')
and doc_info like CONCAT('%',#{searchValue},'%')
ORDER BY doc_seq DESC ) A LIMIT #{pageNo}, #{listSize}

/* 1. ID: selectAdmListCount 2. 업무명: 뉴스 3. 업무설명: 관리자 뉴스 리스트 총갯수 */
SELECT COUNT(1) FROM CRBN_QNA WHERE party_cd = #{partyCd}
and doc_title like CONCAT('%',#{searchValue},'%')
and doc_info like CONCAT('%',#{searchValue},'%')

/*
    1. ID: selectListCount
    2. 업무명: 뉴스
    3. 업무설명: 뉴스 리스트 총갯수
*/

SELECT
    COUNT(1)
FROM CRBN_QNA
  WHERE  party_cd = #{partyCd} 
 LIMIT #{pageNo}, #{listSize}

mapper.insert:

/*
    1. ID: insert
    2. 업무명: 뉴스
    3. 업무설명: 뉴스 등록
*/
INSERT INTO CRBN_QNA (
    party_cd, mbr_id, doc_title, doc_info
) VALUES (
  #{partyCd}
, #{mbrId}
, #{docTitle}
, #{docInfo}
)

mapper.update:

/*
    1. ID: update
    2. 업무명: 뉴스
    3. 업무설명: 뉴스 변경
*/
UPDATE CRBN_QNA
   SET
        doc_title = #{docTitle}
        , doc_info = #{docInfo}
        ,cre_dtm = now()
  WHERE doc_seq = #{docSeq}


/*
    1. ID: updateReply
    2. 업무명: QNA
    3. 업무설명: 답글
*/
UPDATE CRBN_QNA
   SET
        audit_ㅑd = #{auditId}
        , ans_content = #{ansContent}
        ,ans_dtm = now()
  WHERE doc_seq = #{docSeq}
